geofence_node.sourceCode:
// Geofence Checker: GPS 위치가 설정된 폴리곤 내부인지 확인
// globalVariables에 geofence_lat, geofence_lon 배열 설정 필요
// Indicator: /studio_script/geofence.inside (boolean)

import { Input } from "./types";

export const inputs = ["/sensor/gps"];
export const output = "/studio_script/geofence";

// 기본 사각형 지오펜스 (globalVariables 미설정 시 사용)
// 영월 기준 대략적인 테스트 영역
const DEFAULT_FENCE = [
  { lat: 37.180, lon: 128.460 },
  { lat: 37.185, lon: 128.460 },
  { lat: 37.185, lon: 128.465 },
  { lat: 37.180, lon: 128.465 },
];

function pointInPolygon(lat: number, lon: number, polygon: Array<{lat: number, lon: number}>): boolean {
  let inside = false;
  const n = polygon.length;
  for (let i = 0, j = n - 1; i < n; j = i++) {
    const yi = polygon[i].lat, xi = polygon[i].lon;
    const yj = polygon[j].lat, xj = polygon[j].lon;
    if (((yi > lat) !== (yj > lat)) && (lon < (xj - xi) * (lat - yi) / (yj - yi) + xi)) {
      inside = !inside;
    }
  }
  return inside;
}

type InputEvent = Input<"/sensor/gps">;

export default function script(event: InputEvent): {
  inside: boolean;
  latitude: number;
  longitude: number;
} | undefined {
  const msg = (event as any).message;
  const lat = msg.latitude;
  const lon = msg.longitude;

  if (lat === 0 && lon === 0) return undefined; // GPS 미수신

  const fence = DEFAULT_FENCE;
  const inside = pointInPolygon(lat, lon, fence);

  return { inside, latitude: lat, longitude: lon };
}

perception_mode_node.sourceCode:
// Perception Mode Display: Hybrid E2E 상태 토픽에서 현재 모드 추출
// Indicator: /studio_script/perception_mode.mode
// Phase 3.1에서 /hybrid_e2e/status 토픽 발행 후 동작

import { Input } from "./types";

export const inputs = ["/hybrid_e2e/status"];
export const output = "/studio_script/perception_mode";

type InputEvent = Input<"/hybrid_e2e/status">;

export default function script(event: InputEvent): {
  mode: string;
  safety: string;
  label: string;
} | undefined {
  const msg = (event as any).message;

  try {
    const status = JSON.parse(msg.data);
    const mode = status.mode || "unknown";
    const safety = status.safety_state || "unknown";

    const modeLabels: Record<string, string> = {
      learned: "AI",
      traditional: "Classic",
      fallback: "FALLBACK",
      auto: "Auto",
    };

    return {
      mode,
      safety,
      label: modeLabels[mode] || mode.toUpperCase(),
    };
  } catch {
    return undefined;
  }
}
